package org.apache.commons.lang3.text.translate.steps;

import io.cucumber.java.en.*;
import org.apache.commons.lang3.text.translate.CharSequenceTranslator;
import org.apache.commons.lang3.text.translate.LookupTranslator;
import org.apache.commons.lang3.StringEscapeUtils;
import static org.junit.Assert.*;

import java.io.IOException;
import java.io.StringWriter;
import java.util.HashMap;
import java.util.Map;

public class StepDefs {

    private CharSequenceTranslator translator;
    private CharSequence input;
    private String result;

    @Given("a CharSequenceTranslator instance \\(e\\.g\\. StringEscapeUtils\\.ESCAPE_XML\\)")
    public void a_CharSequenceTranslator_instance_e_g_StringEscapeUtils_ESCAPE_XML() {
        // Use a custom translator to simulate the bug scenario
        // We'll use a simple identity translator to see if surrogate pairs are handled correctly
        Map<CharSequence, CharSequence> lookupMap = new HashMap<>();
        translator = new LookupTranslator(lookupMap);
    }

    @When("translating a CharSequence containing a surrogate pair \\(e\\.g\\. \"([^\"]*)\"\\) followed by a regular character \\(e\\.g\\. \"([^\"]*)\"\\)")
    public void translating_a_CharSequence_containing_a_surrogate_pair_followed_by_a_regular_character(String surrogatePair, String regularChar) {
        input = surrogatePair + regularChar;

        try {
            StringWriter writer = new StringWriter();
            translator.translate(input, 0, input.length(), writer);
            result = writer.toString();
        } catch (IOException e) {
            // Handle exception in test
            result = "ERROR: " + e.getMessage();
        }
    }

    @Then("the translator must correctly advance the index past the surrogate pair \\(consuming 2 chars\\)")
    public void the_translator_must_correctly_advance_the_index_past_the_surrogate_pair() {
        // This step will be tested by the following validations
        // The surrogate pair should be processed correctly if the bug is fixed
    }

    @And("the subsequent character \"([^\"]*)\" must be correctly processed and included in the output")
    public void the_subsequent_character_must_be_correctly_processed_and_included_in_the_output(String expectedNextChar) {
        // Check that the result contains the expected content
        // This will fail if the index advancement bug exists
        assertTrue("Output should contain the expected subsequent character: " + expectedNextChar, 
                   result.contains(expectedNextChar));
    }

    @And("the output should match the input \"([^\"]*)\" if no escaping is applied to these characters")
    public void the_output_should_match_the_input_if_no_escaping_is_applied_to_these_characters(String expectedOutput) {
        assertEquals("Output should match input when no escaping is applied", expectedOutput, result);
    }
}

